// History.js
import React, { useEffect, useState } from "react";
import api from "../../api/axios";
import "../admin/Admin.css";

export default function StudentHistory() {
  const [submissions, setSubmissions] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    api.get("/student/submissions").catch(() => ({ data: { data: [] } }))
      .then(r => setSubmissions(r.data.data || []))
      .finally(() => setLoading(false));
  }, []);

  return (
    <div className="admin-page fade-in">
      <div className="page-header"><h1>Lịch sử bài thi</h1><p>Kết quả các bài kiểm tra đã làm</p></div>
      <div className="table-wrapper">
        {loading ? <div className="page-loading"><div className="spinner" /></div> : (
          <table className="data-table">
            <thead><tr><th>Bài kiểm tra</th><th>Điểm</th><th>Thời gian nộp</th><th>Nhận xét AI</th></tr></thead>
            <tbody>
              {submissions.length === 0
                ? <tr><td colSpan={4} className="empty-state"><p>Chưa có bài thi nào</p></td></tr>
                : submissions.map(s => (
                  <tr key={s.id}>
                    <td>Quiz #{s.quizId}</td>
                    <td><strong style={{ color: s.score >= 70 ? "var(--success)" : "var(--danger)" }}>{s.score}</strong>/100</td>
                    <td style={{ fontSize: "0.82rem", color: "var(--gray-500)" }}>{s.submittedAt ? new Date(s.submittedAt).toLocaleString("vi-VN") : "—"}</td>
                    <td style={{ fontSize: "0.82rem" }}>{s.aiComment || "—"}</td>
                  </tr>
                ))
              }
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
}
